    31→sealed class Screen(val route: String, val label: String, val icon: ImageVector) {
    32→    object Home : Screen("home", "Home", Icons.Default.Home)
    33→    object Classes : Screen("classes", "Classes", Icons.Default.DateRange)
    34→    object Bus : Screen("bus", "Bus", Icons.Default.LocationOn)
    35→    object Weather : Screen("weather", "Weather", Icons.Default.Cloud)
    36→    object AddEdit : Screen("add_edit", "Add/Edit", Icons.Default.Add)
    37→    object Notifications : Screen("notifications", "Alerts", Icons.Default.Notifications)
    38→    object CourseDetail : Screen("course_detail/{entryId}", "", Icons.Default.DateRange) {
    39→        fun routeFor(entryId: String) = "course_detail/$entryId"
    40→    }
    41→    object EditEntry : Screen("edit_entry/{entryId}", "", Icons.Default.Add) {
    42→        fun routeFor(entryId: String) = "edit_entry/$entryId"
    43→    }
    44→}
    45→
    46→val bottomNavItems = listOf(
    47→    Screen.Home,
    48→    Screen.Classes,
    49→    Screen.Bus,
    50→    Screen.AddEdit,
    51→    Screen.Weather,
    52→    Screen.Notifications
    53→)
    54→
    55→class MainActivity : ComponentActivity() {
    56→    override fun onCreate(savedInstanceState: Bundle?) {
    57→        super.onCreate(savedInstanceState)
    58→        enableEdgeToEdge()
    59→        setContent {
    60→            Combined_scheduleTheme {
    61→                AppNavigation()
    62→            }
    63→        }
    64→    }
    65→}
    66→
    67→@Composable
    68→fun AppNavigation() {
    69→    val navController = rememberNavController()
    70→    val navBackStackEntry by navController.currentBackStackEntryAsState()
    71→    val currentDestination = navBackStackEntry?.destination
    72→    val isDetailScreen = currentDestination?.route?.startsWith("course_detail") == true
    73→        || currentDestination?.route?.startsWith("edit_entry") == true
    74→
    75→    Scaffold(
    76→        bottomBar = {
    77→            if (!isDetailScreen) NavigationBar {
    78→                bottomNavItems.forEach { screen ->
    79→                    NavigationBarItem(
    80→                        icon = { Icon(screen.icon, contentDescription = screen.label) },
    81→                        label = { Text(screen.label) },
    82→                        selected = currentDestination?.hierarchy?.any { it.route == screen.route } == true,
    83→                        onClick = {
    84→                            navController.navigate(screen.route) {
    85→                                popUpTo(navController.graph.findStartDestination().id) {
    86→                                    saveState = true
    87→                                }
    88→                                launchSingleTop = true
    89→                                restoreState = true
    90→                            }
    91→                        }
    92→                    )
    93→                }
    94→            }
    95→        }
    96→    ) { innerPadding ->
    97→        NavHost(
    98→            navController = navController,
    99→            startDestination = Screen.Home.route,
   100→            modifier = Modifier.padding(innerPadding)
   101→        ) {
   102→            composable(Screen.Home.route) {
   103→                HomeScreen(
   104→                    onNavigateToAddEdit = {
   105→                        navController.navigate(Screen.AddEdit.route) {
   106→                            launchSingleTop = true
   107→                        }
   108→                    },
   109→                    onNavigateToNotifications = {
   110→                        navController.navigate(Screen.Notifications.route) {
   111→                            launchSingleTop = true
   112→                        }
   113→                    },
   114→                    onCourseClick = { entry ->
   115→                        navController.navigate(Screen.CourseDetail.routeFor(entry.id))
   116→                    },
   117→                    onEditEntry = { entryId ->
   118→                        navController.navigate(Screen.EditEntry.routeFor(entryId))
   119→                    }
   120→                )
   121→            }
   122→            composable(Screen.Classes.route) { ClassScheduleScreen() }
   123→            composable(Screen.Bus.route) { BusScheduleScreen() }
   124→            composable(Screen.Weather.route) { WeatherScreen() }
   125→            composable(Screen.AddEdit.route) { AddEditEntryScreen(onBack = { navController.popBackStack() }) }
   126→            composable(Screen.Notifications.route) { NotificationSettingsScreen() }
   127→            composable(
   128→                route = Screen.CourseDetail.route,
   129→                arguments = listOf(navArgument("entryId") { type = NavType.StringType })
   130→            ) { backStackEntry ->
   131→                val entryId = backStackEntry.arguments?.getString("entryId") ?: return@composable
   132→                CourseDetailScreen(
   133→                    entryId = entryId,
   134→                    onBack = { navController.popBackStack() }
   135→                )
   136→            }
   137→            composable(
   138→                route = Screen.EditEntry.route,
   139→                arguments = listOf(navArgument("entryId") { type = NavType.StringType })
   140→            ) { backStackEntry ->
   141→                val entryId = backStackEntry.arguments?.getString("entryId") ?: return@composable
   142→                AddEditEntryScreen(
   143→                    entryId = entryId,
   144→                    onBack = { navController.popBackStack() }
   145→                )
   146→            }
   147→        }
   148→    }
   149→}
