     8→import com.example.combined_schedule.data.WeatherData
     9→import com.example.combined_schedule.data.WeatherRepository
    10→import com.google.android.gms.location.LocationServices
    11→import kotlinx.coroutines.Dispatchers
    12→import kotlinx.coroutines.flow.MutableStateFlow
    13→import kotlinx.coroutines.flow.StateFlow
    14→import kotlinx.coroutines.flow.asStateFlow
    15→import kotlinx.coroutines.launch
    16→import kotlinx.coroutines.suspendCancellableCoroutine
    17→import kotlinx.coroutines.withContext
    18→import kotlin.coroutines.resume
    19→
    20→sealed class WeatherUiState {
    21→    object Loading : WeatherUiState()
    22→    data class Success(val data: WeatherData) : WeatherUiState()
    23→    data class Error(val message: String) : WeatherUiState()
    24→}
    25→
    26→class WeatherViewModel(app: Application) : AndroidViewModel(app) {
    27→
    28→    private val _uiState = MutableStateFlow<WeatherUiState>(WeatherUiState.Loading)
    29→    val uiState: StateFlow<WeatherUiState> = _uiState.asStateFlow()
    30→
    31→    init {
    32→        // Show cached data immediately if fresh, then refresh in background
    33→        WeatherRepository.getCached()?.let { _uiState.value = WeatherUiState.Success(it) }
    34→        refresh()
    35→    }
    36→
    37→    fun refresh() {
    38→        viewModelScope.launch {
    39→            if (_uiState.value !is WeatherUiState.Success) {
    40→                _uiState.value = WeatherUiState.Loading
    41→            }
    42→            try {
    43→                val (lat, lng) = getLocation()
    44→                val data = withContext(Dispatchers.IO) { WeatherRepository.fetch(lat, lng) }
    45→                _uiState.value = WeatherUiState.Success(data)
    46→            } catch (e: Exception) {
    47→                if (_uiState.value !is WeatherUiState.Success) {
    48→                    _uiState.value = WeatherUiState.Error(
    49→                        if (e.message?.contains("Unable to resolve host") == true ||
    50→                            e.message?.contains("failed to connect") == true)
    51→                            "No internet connection"
    52→                        else
    53→                            "Could not load weather"
    54→                    )
    55→                }
    56→            }
    57→        }
    58→    }
    59→
    60→    @SuppressLint("MissingPermission")
    61→    private suspend fun getLocation(): Pair<Double, Double> =
    62→        suspendCancellableCoroutine { cont ->
    63→            try {
    64→                LocationServices.getFusedLocationProviderClient(getApplication())
    65→                    .lastLocation
    66→                    .addOnSuccessListener { loc ->
    67→                        if (cont.isActive) cont.resume(
    68→                            if (loc != null) loc.latitude to loc.longitude
    69→                            else UIUC_LAT to UIUC_LNG
    70→                        )
    71→                    }
    72→                    .addOnFailureListener {
    73→                        if (cont.isActive) cont.resume(UIUC_LAT to UIUC_LNG)
    74→                    }
    75→            } catch (_: Exception) {
    76→                if (cont.isActive) cont.resume(UIUC_LAT to UIUC_LNG)
    77→            }
    78→        }
    79→
    80→    companion object {
    81→        private const val UIUC_LAT = 40.1020
    82→        private const val UIUC_LNG = -88.2272
    83→    }
    84→
    85→    class Factory(private val app: Application) : ViewModelProvider.Factory {
    86→        @Suppress("UNCHECKED_CAST")
    87→        override fun <T : androidx.lifecycle.ViewModel> create(modelClass: Class<T>): T =
    88→            WeatherViewModel(app) as T
    89→    }
    90→}
